import java.io.IOException;
import java.util.Scanner;

import g1.application.AccountService;
import g1.application.LoadErrorException;
import g1.application.MaterialApplicationService;
import g1.application.ProductApplicationService;
import g1.application.SaveErrorException;
import g1.infrastructure.MaterialRepository;
import g1.infrastructure.AccountRepository;
import g1.infrastructure.ProductRepository;
import g1.presentation.AccountMenu;
import g1.presentation.AdminMenu;
import g1.presentation.InputHandler;
import g1.presentation.LoginMenu;
import g1.presentation.MaterialMenu;
import g1.presentation.productMenu;
import g1.presentation.userMenu;


public class App {
    public String getGreeting() {
        return "Hello World!";

    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        InputHandler input = new InputHandler(scanner);

        MaterialRepository matRepo = new MaterialRepository();
        
        try {
            matRepo.loadFromFile();
        } catch (LoadErrorException e) {
            System.err.println("Load error: " + e.getMessage());
        } catch (IOException e) {                                   // Error handling för att ladda från fil
            System.err.println("File error: " + e.getMessage());
        } catch (ClassNotFoundException e) {
            System.err.println("Class error: " + e.getMessage());
        } catch (SaveErrorException e){
            System.err.println("Save error: " + e.getMessage());
        }
        
        MaterialApplicationService mas = new MaterialApplicationService(matRepo);
        AccountRepository AccountRepo = new AccountRepository();

        try {
            AccountRepo.loadFromFile();
        } catch (LoadErrorException e) {
            System.err.println("Load error: " + e.getMessage());
        } catch (IOException e) {                                   // Error handling för att ladda från fil
            System.err.println("File error: " + e.getMessage());
        } catch (ClassNotFoundException e) {
            System.err.println("Class error: " + e.getMessage());
        } catch (SaveErrorException e) {
            System.err.println("Save error: " + e.getMessage());
        }

        AccountService Acc = new AccountService(AccountRepo);

        ProductRepository productRepo = new ProductRepository();

        try {
            productRepo.loadFromFile();
        } catch (LoadErrorException e) {
            System.err.println("Load error: " + e.getMessage());
        } catch (IOException e) {                                   // Error handling för att ladda från fil
            System.err.println("File error: " + e.getMessage());
        } catch (ClassNotFoundException e) {
            System.err.println("Class error: " + e.getMessage());
        } catch (SaveErrorException e) {
            System.err.println("Save error: " + e.getMessage());
        }

        ProductApplicationService pas = new ProductApplicationService(productRepo, matRepo);
        
        MaterialMenu materialmenu = new MaterialMenu(input, mas);
        productMenu productMenu = new productMenu(input, pas);
        AccountMenu accountMenu = new AccountMenu(input, Acc);
        AdminMenu adminMenu = new AdminMenu(input, materialmenu, productMenu, accountMenu);
        userMenu userMenu = new userMenu(input, materialmenu, productMenu);
        LoginMenu loginMenu = new LoginMenu(input, adminMenu, userMenu, Acc);
        loginMenu.runMenu();

        scanner.close();


    }
}
